    slides: [{ imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2F2be2ede8-a97c-403a-bd89-9ad106d6922a', text: 'Things to NOT do if you have severe anxiety' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Fd2333782-df3f-4a1b-9528-50f82049852a', text: '(From someone who has recovered from chronic anxiety)' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Ffa242f75-6ea8-4c04-8d99-f0c3438085c2', text: 'Don’t avoid going places' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Fa827aa25-e5ac-4bc6-bd17-129f72f087a4', text: 'Anxiety recovery is about teaching your body safety in places like work, school, grocery stores, and airplanes. Exposure is the only way to recover.' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2F15190a2b-caa0-4944-9c8b-4c5125f5d29a', text: 'Don’t research symptoms' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Fbe245479-990c-434d-aef9-63bad774f6e3', text: 'Searching your symptoms on Google or Reddit only keeps you in the anxiety cycle and does not give your nervous system the break it needs to heal.' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Ff36e8f1e-edac-491c-9ac4-7659de1b24b6', text: 'Don’t run to a Psychiatrist.' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Fe3d16b49-69c3-4283-98cf-37adf156a35b', text: 'Psychiatrists focus on symptom management, not long term recovery. They will NEVER search for a root cause. It’s best to get full blood work to pin...' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2F44395e78-2953-483d-9754-5301360e0001', text: '**NEVER LET ANY DOCTOR PRESCRIBE A BENZO' }, { imageUrl: 'https://media.aftermark.ai/trending_content%2Fslideshow%2Fc50d6951-95a3-43df-90b9-d8a5349bc14c', text: 'Don’t consume refined sugar, food dyes, or artificial sweeteners.' }],
