    slides: [{ imageUrl: 'https://media.aftermark.workers.dev/images/3fce7b7392c940d2a98bdb2860617417.webp', text: '8 Reasons Men Lose Themselves in the Wrong Relationship' }, { imageUrl: 'https://media.aftermark.workers.dev/images/cd9f74fde0d8499ba33d5350024f0e10.webp', text: '1. You ignored your gut because you were addicted to her potential' }, { imageUrl: 'https://media.aftermark.workers.dev/images/379f81e020f1413c8d9459db4ca3186b.webp', text: '2. You mistook chaos for passion.' }, { imageUrl: 'https://media.aftermark.workers.dev/images/949c6bae8ac74511903c67fc157e213f.webp', text: '3. You lost your identity trying to become her idea of "enough"' }, { imageUrl: 'https://media.aftermark.workers.dev/images/b3fad7e88ad0463b8b901548530b3e18.webp', text: '4. You kept pouring into someone who only took.' }, { imageUrl: 'https://media.aftermark.workers.dev/images/04f3ddd34ae84d2691f53f69295d1984.webp', text: '5. You tolerated disrespect just to avoid being alone' }, { imageUrl: 'https://media.aftermark.workers.dev/images/af76cf7991344fabbd964063587bbe51.webp', text: '6. You stayed hoping the version of her you loved would come back' }, { imageUrl: 'https://media.aftermark.workers.dev/images/37510382b6794aa5adf3a5de48c8e6d8.webp', text: '7. You confused emotional dependency with loyalty' }, { imageUrl: 'https://media.aftermark.workers.dev/images/873e094f4e0d487f87ec0d7ba8aecf18.webp', text: '8. You forgot that peace > love. Get your self-respect back. Lock in' }],
