// Helper: get content filtered by type
export const getByType = (type) => {
  const map = {
    slideshow: "slideshow",
    "wall-of-text": "wall-of-text",
    walloftext: "wall-of-text",
    "video-hook-and-demo": "video-hook-and-demo",
    "video-hook": "video-hook-and-demo",
    videohook: "video-hook-and-demo",
    "green-screen-meme": "green-screen-meme",
    "green-screen": "green-screen-meme",
    greenscreen: "green-screen-meme",
  };
  const t = map[type] || type;
  return VIRAL_CONTENT.filter((v) => v.contentType === t);
};

// Default slideshow placeholder image (Pinterest / Aftermark CDN)
export const DEFAULT_SLIDESHOW_PLACEHOLDER =
  "https://i.pinimg.com/1200x/33/04/18/330418dacabe4b566cccffa2aa9dc307.jpg";

// Helper: format big numbers like TikTok
export const fmtNum = (n) => {
  if (!n) return "0";
  if (n >= 1000000) return (n / 1000000).toFixed(1).replace(".0", "") + "M";
  if (n >= 1000) return (n / 1000).toFixed(1).replace(".0", "") + "K";
  return String(n);
};
